from fractions import Fraction

def polygon_area(vertices):
    N = len(vertices)
    area = 0.0
    for i in range(N):
        j = (i + 1) % N
        area += vertices[i][0] * vertices[j][1]
        area -= vertices[j][0] * vertices[i][1]
    area = abs(area) / 2.0
    return area

def point_in_polygon(point, vertices):
    x, y = point
    N = len(vertices)
    inside = False
    p1x, p1y = vertices[0]
    for i in range(N+1):
        p2x, p2y = vertices[i % N]
        if min(p1y, p2y) < y <= max(p1y, p2y):
            if x <= max(p1x, p2x):
                if p1y != p2y:
                    xinters = (y - p1y) * (p2x - p1x) / (p2y - p1y) + p1x
                if p1x == p2x or x <= xinters:
                    inside = not inside
        p1x, p1y = p2x, p2y
    return inside

def line_intersection(line1, line2):
    x1, y1 = line1[0]
    x2, y2 = line1[1]
    x3, y3 = line2[0]
    x4, y4 = line2[1]
    denom = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4)
    if denom == 0:
        return None
    t = ((x1 - x3) * (y3 - y4) - (y1 - y3) * (x3 - x4)) / denom
    u = ((x1 - x3) * (y2 - y1) - (y1 - y3) * (x2 - x1)) / denom
    if 0 <= t <= 1 and 0 <= u <= 1:
        return ((x1 + t * (x2 - x1)), (y1 + t * (y2 - y1)))
    else:
        return None

def clip(subject_polygon, clip_polygon):
    def inside(p):
        return (cp2[0] - cp1[0]) * (p[1] - cp1[1]) > (cp2[1] - cp1[1]) * (p[0] - cp1[0])

    def compute_intersection():
        dc = [cp1[0] - cp2[0], cp1[1] - cp2[1]]
        dp = [s[0] - e[0], s[1] - e[1]]
        n1 = cp1[0] * cp2[1] - cp1[1] * cp2[0]
        n2 = s[0] * e[1] - s[1] * e[0]
        n3 = 1.0 / (dc[0] * dp[1] - dc[1] * dp[0])
        return ((n1 * dp[0] - n2 * dc[0]) * n3, (n1 * dp[1] - n2 * dc[1]) * n3)

    output_list = subject_polygon
    cp1 = clip_polygon[-1]

    for clip_edge in clip_polygon:
        cp2 = clip_edge
        input_list = output_list
        output_list = []
        s = input_list[-1]

        for e in input_list:
            if inside(e):
                if not inside(s):
                    output_list.append(compute_intersection())
                output_list.append(e)
            elif inside(s):
                output_list.append(compute_intersection())
            s = e
        cp1 = cp2
    return output_list

def main():
    N, Q = map(int, input().split())
    vertices = [tuple(map(float, input().split())) for _ in range(N)]

    for _ in range(Q):
        r, c = map(float, input().split())
        pixel = [(r-0.5, c-0.5), (r-0.5, c+0.5), (r+0.5, c+0.5), (r+0.5, c-0.5)]
        clipped = clip(pixel, vertices)
        if len(clipped) == 0:
            area = 0.0
        else:
            area = polygon_area(clipped)
        fraction = Fraction(area).limit_denominator()
        print(f'{fraction.numerator}/{fraction.denominator}')

