from fractions import Fraction

def sign(p1, p2, p3):
    """Calculate the sign of the determinant of vectors p1->p2 and p1->p3."""
    return (p1[0] - p3[0]) * (p2[1] - p3[1]) - (p2[0] - p3[0]) * (p1[1] - p3[1])

def point_in_polygon(pt, vertices):
    """Check if a point is inside the polygon defined by vertices."""
    N = len(vertices)
    inside = True
    for i in range(N):
        j = (i + 1) % N
        if sign(pt, vertices[i], vertices[j]) < 0:
            inside = False
            break
    return inside

def main():
    N, Q = map(int, input().split())
    vertices = [tuple(map(float, input().split())) for _ in range(N)]

    for _ in range(Q):
        r, c = map(float, input().split())
        # Divide the pixel into 32x32 grid and count points inside the polygon
        count = 0
        total = 32 * 32
        for i in range(32):
            for j in range(32):
                x = c - 0.5 + (j + 0.5) / 32
                y = r - 0.5 + (i + 0.5) / 32
                if point_in_polygon((x, y), vertices):
                    count += 1
        fraction = Fraction(count, total).limit_denominator()
        print(f'{fraction.numerator}/{fraction.denominator}')

if __name__ == "__main__":
    main()
