    input = sys.stdin.readline
    N, S = map(int, input().split())

    size = [0] * (N + 1)
    power = [0] * (N + 1)
    graph = defaultdict(list)

    for i in range(1, N + 1):
        s, p = map(int, input().split())
        size[i] = s
        power[i] = p

    for _ in range(N - 1):
        u, v = map(int, input().split())
        graph[u].append(v)
        graph[v].append(u)

    parent = [-1] * (N + 1)
    order = []
    stack = [1]

    while stack:
        node = stack.pop()
        order.append(node)
        for neighbor in graph[node]:
            if neighbor == parent[node]:
                continue
            parent[neighbor] = node
            stack.append(neighbor)

    order.reverse()

    dp = [[-float('inf')] * (S + 1) for _ in range(N + 1)]

    for node in order:
        dp[node][0] = 0
        for s in range(S + 1):
            if s + size[node] <= S:
                dp[node][s + size[node]] = max(dp[node][s + size[node]], dp[node][s] + power[node])
        for neighbor in graph[node]:
            if neighbor == parent[node]:
                continue
            new_dp = [[-float('inf')] * (S + 1) for _ in range(1)]
            for s1 in range(S + 1):
                for s2 in range(S + 1 - s1):
                    new_dp[0][s1 + s2] = max(new_dp[0][s1 + s2], dp[node][s1] + dp[neighbor][s2])
            dp[node] = new_dp[0]

    ans = 0
