import itertools

def calculate_card_value(card):
    if card in ['J', 'Q', 'K']:
        return 10
    elif card == 'T':
        return 10
    elif card == 'A':
        return 1
    else:
        return int(card)

def calculate_combinations(hand):
    total_score = 0
    # Calculate 15's
    for r in range(2, len(hand) + 1):
        for combination in itertools.combinations(hand, r):
            if sum(calculate_card_value(card) for card in combination) == 15:
                total_score += 2
    # Calculate pairs
    for r in range(2, len(hand) + 1):
        for combination in itertools.combinations(hand, r):
            if len(set(combination)) == 1:
                total_score += 2 * (r * (r - 1) // 2)
                break
    # Calculate runs
    card_values = sorted([calculate_card_value(card) for card in hand])
    run_scores = []
    current_run = []
    for value in card_values:
        if not current_run or value == current_run[-1] + 1:
            current_run.append(value)
        else:
            if len(current_run) >= 3:
                run_scores.append(current_run)
            current_run = [value]
    if len(current_run) >= 3:
        run_scores.append(current_run)
    for run in run_scores:
        count_dict = {}
        for card in hand:
            value = calculate_card_value(card)
            if value in run:
                count_dict[value] = count_dict.get(value, 0) + 1
        total_score += len(run) * count_dict[run[0]]
        for i in range(1, len(run)):
            count_dict[run[i]] *= count_dict[run[i - 1]]
            total_score *= count_dict[run[i]]
    return total_score

def main():
