import sys

def read_input():
    m, n, k, s = map(int, sys.stdin.readline().strip().split())
    x = sorted(list(map(float, sys.stdin.readline().strip().split())))
    y = sorted(list(map(float, sys.stdin.readline().strip().split())))
    return m, n, k, s, x, y

def cost(points, start, end):
    centroid = (points[start] + points[end]) / 2
    return sum((x - centroid) ** 2 for x in points[start:end+1])

def calculate_dp(points, k):
    n = len(points)
    dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
    dp[0][0] = 0
    for i in range(1, n + 1):
        dp[i][1] = cost(points, 0, i - 1)
    for j in range(2, k + 1):
        for i in range(j, n + 1):
            for start in range(j - 1, i):
                dp[i][j] = min(dp[i][j], dp[start][j-1] + cost(points, start, i - 1))
    return dp[n][k]

def main():
    m, n, k, s, x, y = read_input()
    combined = sorted(x + y)
    result = calculate_dp(x, k) + calculate_dp(y, k) + (m + n) * (s / 2) ** 2
    print(f'{result:.10f}')

if __name__ == '__main__':
    main()
