import sys

def read_input():
    m, n, k, s = map(int, sys.stdin.readline().strip().split())
    x1 = sorted(list(map(float, sys.stdin.readline().strip().split())))
    x2 = sorted(list(map(float, sys.stdin.readline().strip().split())))
    return m, n, k, s, x1, x2

def cost(x, s, points):
    total_cost = 0
    for xi in x:
        min_dist = float('inf')
        for point in points:
            dist = (xi - point) ** 2
            if dist < min_dist:
                min_dist = dist
        total_cost += min_dist
    return total_cost + len(x) * (s / 2) ** 2

def find_min_cost(x, k, s, points):
    n = len(x)
    dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
    dp[0][0] = 0
    for i in range(1, n + 1):
        for j in range(1, min(i, k) + 1):
            for l in range(j - 1, i):
                c = sum((x[r] - x[(l + i) // 2]) ** 2 for r in range(l, i))
                dp[i][j] = min(dp[i][j], dp[l][j - 1] + c)
    return dp[n][k]

